function rateLimitByUser(maxRequests = 100, windowMs = 60000) {
  const userRequests = new Map();

  setInterval(() => {
    const now = Date.now();
    for (const [userId, data] of userRequests.entries()) {
      if (now - data.resetTime > windowMs) {
        userRequests.delete(userId);
      }
    }
  }, windowMs);

  return (req, res, next) => {
    if (!req.user) {
      return next();
    }

    const userId = req.user.id;
    const now = Date.now();
    
    if (!userRequests.has(userId)) {
      userRequests.set(userId, {
        count: 1,
        resetTime: now
      });
      return next();
    }

    const userData = userRequests.get(userId);
    
    if (now - userData.resetTime > windowMs) {
      userData.count = 1;
      userData.resetTime = now;
      return next();
    }

    if (userData.count >= maxRequests) {
      return res.status(429).json({
        error: 'Too many requests',
        code: 'RATE_LIMIT_EXCEEDED',
        retryAfter: Math.ceil((userData.resetTime + windowMs - now) / 1000)
      });
    }

    userData.count++;
    next();
  };
}

